<template>
  <el-card>
    <template #header>
      <div class="card-header">
        <span>文章管理</span>
        <el-button type="primary" @click="$router.push('/articles/create')">
          <el-icon><Plus /></el-icon> 新建文章
        </el-button>
      </div>
    </template>

    <el-table :data="articles" v-loading="loading" style="width: 100%" stripe>
      <el-table-column prop="zh.title" label="标题" min-width="200" show-overflow-tooltip />
      <el-table-column prop="category" label="分类" width="120" />
      <el-table-column label="状态" width="100">
        <template #default="{ row }">
          <el-tag :type="row.status === 'published' ? 'success' : 'info'" round>
            {{ row.status === 'published' ? '已发布' : '草稿' }}
          </el-tag>
        </template>
      </el-table-column>
      <el-table-column label="创建时间" width="180">
        <template #default="{ row }">{{ new Date(row.createdAt).toLocaleString() }}</template>
      </el-table-column>
      <el-table-column label="操作" width="220" fixed="right">
        <template #default="{ row }">
          <el-button type="primary" link @click="$router.push(`/articles/edit/${row.id}`)">编辑</el-button>
          <el-button type="warning" link @click="toggleStatus(row)">{{ row.status === 'published' ? '下架' : '发布' }}</el-button>
          <el-button type="danger" link @click="handleDelete(row.id)">删除</el-button>
        </template>
      </el-table-column>
    </el-table>
  </el-card>
</template>

<script setup>
import { ref, onMounted } from 'vue';
import { ElMessage, ElMessageBox } from 'element-plus';
import { Plus } from '@element-plus/icons-vue';
import request from '../api/request.js';

const articles = ref([]);
const loading = ref(false);

const fetchArticles = async () => {
  loading.value = true;
  try {
    const res = await request.get('/articles');
    if (res.success) articles.value = res.data || [];
  } finally {
    loading.value = false;
  }
};

const toggleStatus = async (row) => {
  const newStatus = row.status === 'published' ? 'draft' : 'published';
  try {
    await request.put(`/articles/${row.id}`, { status: newStatus });
    ElMessage.success('状态已更新');
    fetchArticles();
  } catch (err) {
    console.error(err);
  }
};

const handleDelete = async (id) => {
  try {
    await ElMessageBox.confirm('确定删除此文章吗？此操作不可恢复。', '警告', { type: 'warning' });
    await request.delete(`/articles/${id}`);
    ElMessage.success('删除成功');
    fetchArticles();
  } catch (err) {
    console.error(err);
  }
};

onMounted(fetchArticles);
</script>

<style scoped>
.card-header { display: flex; justify-content: space-between; align-items: center; }
</style>